import React, { useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { Select, StatusBadge, Pagination, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { gtService } from '../../../services/gt/gtService';
import type { CostSheetDto } from '../../../services/gt/models';
import { MONTH_OPTIONS, yearOptions } from '../../../constants/voucher';
import { formatVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import erp from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

const TEST_ID = 'erp-gia-thanh';
const PAGE_SIZE = 20;

const GiaThanhListPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const now = new Date();
  const [month, setMonth] = useState(String(now.getMonth() + 1));
  const [year, setYear] = useState(String(now.getFullYear()));
  const [page, setPage] = useState(1);
  const [items, setItems] = useState<CostSheetDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);

  const handleLoad = useCallback(() => {
    setLoading(true);
    gtService.getCostSheets({ month: Number(month), year: Number(year), page, pageSize: PAGE_SIZE })
      .then(res => { setItems(res.items); setTotalCount(res.totalCount); })
      .catch(err => dispatch(addToast({ message: getApiErrorMessage(err, 'Lỗi tải giá thành'), type: 'error' })))
      .finally(() => setLoading(false));
  }, [month, year, page, dispatch]);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) handleLoad(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [handleLoad]);

  return (
    <div className={erp.page} data-testid={TEST_ID}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}><h1 className={erp.title}><i className="fas fa-industry" /> Giá thành sản xuất</h1></div>
      </div>
      <div className={erp.filtersBar} data-testid={`${TEST_ID}-filters`}>
        <Select value={month} onChange={e => { setMonth(e.target.value); setPage(1); }} options={MONTH_OPTIONS} data-testid={`${TEST_ID}-month`} />
        <Select value={year} onChange={e => { setYear(e.target.value); setPage(1); }} options={yearOptions()} data-testid={`${TEST_ID}-year`} />
        <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={handleLoad} onRefresh={handleLoad} showSearch={false} />
      </div>
      <div className={erp.tableCard} data-testid={`${TEST_ID}-table`}>
        {loading ? <div className={erp.loading}>Đang tải...</div> : items.length === 0 ? <div className={erp.empty}>Không có dữ liệu</div> : (
          <div className={erp.tableWrapper}>
            <table className={erp.table}>
              <thead><tr><th>Mã</th><th>SP</th><th className={erp.colRight}>SL TT</th><th className={erp.colRight}>Tổng GT</th><th className={erp.colRight}>GT đơn vị</th><th>Trạng thái</th></tr></thead>
              <tbody>{items.map(r => (
                <tr key={r.id} data-testid={`${TEST_ID}-row-${r.id}`}>
                  <td><button type="button" className={erp.codeLink} onClick={() => navigate(`/gt/gia-thanh/${r.id}`)}><code>{r.code}</code></button></td>
                  <td>{r.productName ?? r.productCode}</td>
                  <td className={erp.colRight}>{r.actualQty}</td>
                  <td className={erp.colRight}>{formatVnd(r.totalCost)}</td>
                  <td className={erp.colRight}>{formatVnd(r.unitCost)}</td>
                  <td><StatusBadge status={r.status} /></td>
                </tr>
              ))}</tbody>
            </table>
          </div>
        )}
        {totalCount > 0 && (
          <div className={erp.paginationRow}>
            <Pagination currentPage={page} totalPages={Math.ceil(totalCount / PAGE_SIZE)} totalCount={totalCount} pageSize={PAGE_SIZE} onPageChange={setPage} />
          </div>
        )}
      </div>
    </div>
  );
};

export default GiaThanhListPage;
